import android.util.Log
import timber.log.Timber
import okhttp3.logging.HttpLoggingInterceptor
import java.io.PrintWriter
import java.io.StringWriter
import java.util.concurrent.ConcurrentHashMap

class ComprehensiveLogger {
    companion object {
        private const val TAG = "AppLogger"
        private val logger = Timber
        private val requestCache = ConcurrentHashMap<String, Long>()
        
        fun init() {
            if (BuildConfig.DEBUG) {
                logger.plant(Timber.DebugTree())
            } else {
                logger.plant(object : Timber.Tree() {
                    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
                        Log.println(priority, tag ?: TAG, message)
                        t?.let { logException(it) }
                    }
                })
            }
        }
        
        fun logAuthAttempt(username: String, success: Boolean, errorMessage: String? = null) {
            val message = if (success) {
                "AUTH SUCCESS: User $username authenticated successfully"
            } else {
                "AUTH FAILED: User $username failed to authenticate. Error: ${errorMessage ?: "Unknown error"}"
            }
            logger.d(message)
        }
        
        fun logDatabaseQuery(query: String, parameters: Map<String, Any?>) {
            val paramStr = parameters.entries.joinToString(", ") { "${it.key}=${it.value}" }
            logger.d("DB QUERY: $query [Parameters: $paramStr]")
        }
        
        fun logApiRequest(
            url: String,
            method: String,
            headers: Map<String, String>,
            body: String?
        ) {
            val headerStr = headers.entries.joinToString("\n") { "${it.key}: ${it.value}" }
            val message = """
                API REQUEST: $method $url
                Headers:
                $headerStr
                Body: ${body ?: "No body"}
            """.trimIndent()
            logger.v(message)
        }
        
        fun logApiResponse(
            url: String,
            statusCode: Int,
            headers: Map<String, String>,
            body: String?
        ) {
            val headerStr = headers.entries.joinToString("\n") { "${it.key}: ${it.value}" }
            val message = """
                API RESPONSE: $url - Status: $statusCode
                Headers:
                $headerStr
                Body: ${body ?: "No body"}
            """.trimIndent()
            logger.v(message)
        }
        
        fun logException(throwable: Throwable) {
            val sw = StringWriter()
            val pw = PrintWriter(sw)
            throwable.printStackTrace(pw)
            logger.e("EXCEPTION: ${throwable.message}\n${sw.toString()}")
        }
        
        fun logCustomEvent(event: String, data: Map<String, Any?>? = null) {
            val dataStr = data?.entries?.joinToString(", ") { "${it.key}=${it.value}" } ?: "No data"
            logger.d("CUSTOM EVENT: $event [Data: $dataStr]")
        }
    }
}

class AppLoggingInterceptor : HttpLoggingInterceptor.Logger {
    override fun log(message: String) {
        ComprehensiveLogger.logCustomEvent("HTTP_LOG", mapOf("message" to message))
